const C = {
  dark: "#1C2533", dark2: "#212E3F", green: "#3AE860", greenDark: "#1A5530",
  gray: "#888888", grayLight: "#AABBC8", white: "#FFFFFF", light: "#F3F3F3"
};

const fmt = (n) => {
  if (n === null || n === undefined) return "—";
  if (n >= 1000000) return (n/1000000).toFixed(1) + "M";
  if (n >= 1000) return (n/1000).toFixed(1) + "k";
  return n.toLocaleString("pt-BR");
};
const fmtBRL = (n) => n === null || n === undefined ? "—" : "R$ " + n.toLocaleString("pt-BR", {minimumFractionDigits:2, maximumFractionDigits:2});
const fmtPct = (n) => n === null || n === undefined ? "—" : n.toFixed(2) + "%";

export default function Dashboard() {
  const [source, setSource] = useState("both");
  const [dateFrom, setDateFrom] = useState("");
  const [dateTo, setDateTo] = useState("");
  const [sortCol, setSortCol] = useState("date");
  const [sortDir, setSortDir] = useState("desc");
  const [page, setPage] = useState(0);
  const [rightMetric, setRightMetric] = useState("contacts");
  const pageSize = 20;

  const metricOptions = {
    spend: { label: "Valor Usado", fmtTip: v => "R$ " + v.toFixed(2), color: "#3AE860" },
    impressions: { label: "Impressoes", fmtTip: v => v.toLocaleString("pt-BR"), color: "#3AE860" },
    clicks: { label: "Cliques", fmtTip: v => v.toLocaleString("pt-BR"), color: "#3AE860" },
    conv_rate: { label: "Tx Conversao", fmtTip: v => v.toFixed(2) + "%", color: "#3AE860" },
    contacts: { label: "Contatos", fmtTip: v => v.toLocaleString("pt-BR"), color: "#3AE860" },
    cost_per_contact: { label: "Custo/Contato", fmtTip: v => v !== null ? "R$ " + v.toFixed(2) : "—", color: "#3AE860" }
  };

  const data = useMemo(() => {
    let rows = [];
    if (source === "meta" || source === "both") {
      META_RAW.forEach(r => rows.push({...r, source: "Meta Ads"}));
    }
    if (source === "google" || source === "both") {
      GOOGLE_RAW.forEach(r => rows.push({...r, source: "Google Ads"}));
    }
    if (source === "both") {
      // Aggregate by date
      const byDate = {};
      rows.forEach(r => {
        if (!byDate[r.date]) byDate[r.date] = {date: r.date, spend:0, impressions:0, clicks:0, contacts:0, source:"Meta + Google"};
        const d = byDate[r.date];
        d.spend += r.spend;
        d.impressions += r.impressions;
        d.clicks += r.clicks;
        d.contacts += r.contacts;
      });
      rows = Object.values(byDate).map(d => ({
        ...d,
        conv_rate: d.clicks > 0 ? (d.contacts / d.clicks) * 100 : 0,
        cost_per_contact: d.contacts > 0 ? d.spend / d.contacts : null
      }));
    }
    // Filter dates
    if (dateFrom) rows = rows.filter(r => r.date >= dateFrom);
    if (dateTo) rows = rows.filter(r => r.date <= dateTo);
    return rows;
  }, [source, dateFrom, dateTo]);

  const sorted = useMemo(() => {
    const s = [...data].sort((a, b) => {
      let va = a[sortCol], vb = b[sortCol];
      if (va === null) va = -Infinity;
      if (vb === null) vb = -Infinity;
      if (typeof va === "string") return sortDir === "asc" ? va.localeCompare(vb) : vb.localeCompare(va);
      return sortDir === "asc" ? va - vb : vb - va;
    });
    return s;
  }, [data, sortCol, sortDir]);

  const paged = sorted.slice(page * pageSize, (page + 1) * pageSize);
  const totalPages = Math.ceil(sorted.length / pageSize);

  const kpis = useMemo(() => {
    const spend = data.reduce((s,r) => s + r.spend, 0);
    const impressions = data.reduce((s,r) => s + r.impressions, 0);
    const clicks = data.reduce((s,r) => s + r.clicks, 0);
    const contacts = data.reduce((s,r) => s + r.contacts, 0);
    return {
      spend, impressions, clicks, contacts,
      conv_rate: clicks > 0 ? (contacts / clicks) * 100 : 0,
      cost_per_contact: contacts > 0 ? spend / contacts : null
    };
  }, [data]);

  const chartData = useMemo(() => {
    const byDate = {};
    data.forEach(r => {
      byDate[r.date] = r;
    });
    return Object.values(byDate).sort((a,b) => a.date.localeCompare(b.date));
  }, [data]);

  // Last 30 days chart data
  const chart30 = useMemo(() => chartData.slice(-30), [chartData]);

  const toggleSort = (col) => {
    if (sortCol === col) setSortDir(d => d === "asc" ? "desc" : "asc");
    else { setSortCol(col); setSortDir("desc"); }
    setPage(0);
  };

  const arrow = (col) => sortCol === col ? (sortDir === "asc" ? " \u25B2" : " \u25BC") : "";

  const btnStyle = (active) => ({
    padding: "8px 20px", border: "none", borderRadius: 6, cursor: "pointer", fontFamily: "Poppins, sans-serif",
    fontSize: 13, fontWeight: 600, transition: "all .2s",
    background: active ? C.green : C.dark2, color: active ? C.dark : C.grayLight,
    boxShadow: active ? "0 0 12px rgba(58,232,96,.3)" : "none"
  });

  return (
    <div style={{background: C.dark, minHeight: "100vh", color: C.white, fontFamily: "Inter, sans-serif", padding: "0"}}>
      {/* Header */}
      <div style={{background: C.dark2, padding: "24px 32px", display: "flex", alignItems: "center", justifyContent: "space-between", borderBottom: "2px solid " + C.greenDark}}>
        <div>
          <div style={{fontFamily: "Poppins, sans-serif", fontSize: 24, fontWeight: 700, letterSpacing: -0.5}}>
            Dashboard de <span style={{color: C.green}}>Performance</span>
          </div>
          <div style={{fontSize: 12, color: C.grayLight, marginTop: 4}}>
            agencia<span style={{color: C.green, fontWeight: 700}}>.</span>wbp | comunicacao e marketing
          </div>
        </div>
        <div style={{display: "flex", gap: 8}}>
          <button style={btnStyle(source==="meta")} onClick={() => {setSource("meta"); setPage(0);}}>Meta Ads</button>
          <button style={btnStyle(source==="google")} onClick={() => {setSource("google"); setPage(0);}}>Google Ads</button>
          <button style={btnStyle(source==="both")} onClick={() => {setSource("both"); setPage(0);}}>Todos</button>
        </div>
      </div>

      <div style={{padding: "24px 32px"}}>
        {/* Date filter */}
        <div style={{display: "flex", flexDirection: "column", gap: 10, marginBottom: 24}}>
          <div style={{display: "flex", gap: 8, alignItems: "center", flexWrap: "wrap"}}>
            <span style={{fontSize: 12, color: C.grayLight, fontWeight: 600, textTransform: "uppercase", letterSpacing: 1}}>Periodo:</span>
            {(() => {
              const today = new Date();
              const iso = d => d.toISOString().slice(0,10);
              const presets = [
                { label: "Ontem", fn: () => { const y = new Date(today); y.setDate(y.getDate()-1); return [iso(y), iso(y)]; }},
                { label: "7 dias", fn: () => { const d = new Date(today); d.setDate(d.getDate()-6); return [iso(d), iso(today)]; }},
                { label: "14 dias", fn: () => { const d = new Date(today); d.setDate(d.getDate()-13); return [iso(d), iso(today)]; }},
                { label: "30 dias", fn: () => { const d = new Date(today); d.setDate(d.getDate()-29); return [iso(d), iso(today)]; }},
                { label: "Mes anterior", fn: () => { const s = new Date(today.getFullYear(), today.getMonth()-1, 1); const e = new Date(today.getFullYear(), today.getMonth(), 0); return [iso(s), iso(e)]; }},
                { label: "Mes atual", fn: () => { const s = new Date(today.getFullYear(), today.getMonth(), 1); return [iso(s), iso(today)]; }},
                { label: "Este ano", fn: () => { const s = new Date(today.getFullYear(), 0, 1); return [iso(s), iso(today)]; }},
              ];
              const chipStyle = (active) => ({
                padding: "5px 14px", border: "1px solid " + (active ? C.green : C.greenDark), borderRadius: 20, cursor: "pointer",
                fontSize: 11, fontWeight: 500, fontFamily: "Inter, sans-serif", transition: "all .2s",
                background: active ? C.green + "22" : "transparent", color: active ? C.green : C.grayLight
              });
              return presets.map((p, i) => {
                const [pFrom, pTo] = p.fn();
                const active = dateFrom === pFrom && dateTo === pTo;
                return <button key={i} style={chipStyle(active)} onClick={() => { setDateFrom(pFrom); setDateTo(pTo); setPage(0); }}>{p.label}</button>;
              });
            })()}
            {(dateFrom || dateTo) && <button onClick={() => {setDateFrom(""); setDateTo(""); setPage(0);}}
              style={{padding: "5px 14px", border: "1px solid " + C.gray, borderRadius: 20, cursor: "pointer", fontSize: 11, fontWeight: 500, fontFamily: "Inter, sans-serif", background: "transparent", color: C.grayLight}}>Limpar</button>}
          </div>
          <div style={{display: "flex", gap: 12, alignItems: "center"}}>
            <input type="date" value={dateFrom} onChange={e => {setDateFrom(e.target.value); setPage(0);}}
              style={{background: C.dark2, border: "1px solid " + C.greenDark, borderRadius: 6, padding: "6px 12px", color: C.white, fontSize: 13, fontFamily: "Inter"}} />
            <span style={{color: C.grayLight, fontSize: 12}}>ate</span>
            <input type="date" value={dateTo} onChange={e => {setDateTo(e.target.value); setPage(0);}}
              style={{background: C.dark2, border: "1px solid " + C.greenDark, borderRadius: 6, padding: "6px 12px", color: C.white, fontSize: 13, fontFamily: "Inter"}} />
            <span style={{marginLeft: "auto", fontSize: 12, color: C.gray}}>{data.length} dias</span>
          </div>
        </div>

        {/* KPI Cards */}
        <div style={{display: "grid", gridTemplateColumns: "repeat(6, 1fr)", gap: 16, marginBottom: 28}}>
          {[
            {label: "Valor Usado", value: fmtBRL(kpis.spend), sub: "total investido"},
            {label: "Impressoes", value: fmt(kpis.impressions), sub: "alcance"},
            {label: "Cliques", value: fmt(kpis.clicks), sub: "todos"},
            {label: "Tx Conversao", value: fmtPct(kpis.conv_rate), sub: "cliques > contatos"},
            {label: "Contatos", value: kpis.contacts.toLocaleString("pt-BR"), sub: "por mensagem"},
            {label: "Custo/Contato", value: fmtBRL(kpis.cost_per_contact), sub: "medio"}
          ].map((k, i) => (
            <div key={i} style={{background: C.dark2, borderRadius: 10, padding: "20px 16px", position: "relative", overflow: "hidden"}}>
              <div style={{position: "absolute", top: 0, left: 0, width: 4, height: "100%", background: C.green, borderRadius: "10px 0 0 10px"}} />
              <div style={{fontSize: 10, color: C.grayLight, textTransform: "uppercase", letterSpacing: 1.5, fontWeight: 600, marginBottom: 8}}>{k.label}</div>
              <div style={{fontSize: 22, fontWeight: 700, fontFamily: "Poppins, sans-serif", color: C.green}}>{k.value}</div>
              <div style={{fontSize: 10, color: C.gray, marginTop: 4}}>{k.sub}</div>
            </div>
          ))}
        </div>

        {/* Charts */}
        <div style={{display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 28}}>
          <div style={{background: C.dark2, borderRadius: 10, padding: "20px"}}>
            <div style={{fontSize: 13, fontWeight: 600, color: C.grayLight, marginBottom: 16, fontFamily: "Poppins"}}>Investimento Diario (ultimos 30 dias)</div>
            <ResponsiveContainer width="100%" height={200}>
              <BarChart data={chart30}>
                <CartesianGrid strokeDasharray="3 3" stroke={C.greenDark} />
                <XAxis dataKey="date" tick={{fill: C.gray, fontSize: 9}} tickFormatter={d => d.slice(5)} />
                <YAxis tick={{fill: C.gray, fontSize: 9}} />
                <Tooltip contentStyle={{background: C.dark, border: "1px solid " + C.greenDark, borderRadius: 8, color: C.white, fontSize: 12}}
                  formatter={(v) => ["R$ " + v.toFixed(2), "Spend"]} labelFormatter={l => l} />
                <Bar dataKey="spend" fill={C.green} radius={[3,3,0,0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
          <div style={{background: C.dark2, borderRadius: 10, padding: "20px"}}>
            <div style={{display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16}}>
              <div style={{fontSize: 13, fontWeight: 600, color: C.grayLight, fontFamily: "Poppins"}}>{metricOptions[rightMetric].label} (ultimos 30 dias)</div>
              <select value={rightMetric} onChange={e => setRightMetric(e.target.value)}
                style={{background: C.dark, border: "1px solid " + C.greenDark, borderRadius: 6, padding: "5px 10px", color: C.green, fontSize: 12, fontFamily: "Inter", fontWeight: 600, cursor: "pointer", outline: "none"}}>
                {Object.entries(metricOptions).map(([k, v]) => (
                  <option key={k} value={k} style={{background: C.dark, color: C.white}}>{v.label}</option>
                ))}
              </select>
            </div>
            <ResponsiveContainer width="100%" height={200}>
              <LineChart data={chart30}>
                <CartesianGrid strokeDasharray="3 3" stroke={C.greenDark} />
                <XAxis dataKey="date" tick={{fill: C.gray, fontSize: 9}} tickFormatter={d => d.slice(5)} />
                <YAxis tick={{fill: C.gray, fontSize: 9}} />
                <Tooltip contentStyle={{background: C.dark, border: "1px solid " + C.greenDark, borderRadius: 8, color: C.white, fontSize: 12}}
                  formatter={(v) => [metricOptions[rightMetric].fmtTip(v), metricOptions[rightMetric].label]} />
                <Line type="monotone" dataKey={rightMetric} stroke={C.green} strokeWidth={2} dot={{r: 2, fill: C.green}} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Table */}
        <div style={{background: C.dark2, borderRadius: 10, overflow: "hidden"}}>
          <div style={{padding: "16px 20px", borderBottom: "1px solid " + C.greenDark, display: "flex", justifyContent: "space-between", alignItems: "center"}}>
            <span style={{fontSize: 14, fontWeight: 600, fontFamily: "Poppins", color: C.grayLight}}>Dia a Dia</span>
            <span style={{fontSize: 11, color: C.gray}}>Pagina {page+1} de {totalPages} | Clique no cabecalho para ordenar</span>
          </div>
          <div style={{overflowX: "auto"}}>
            <table style={{width: "100%", borderCollapse: "collapse", fontSize: 12}}>
              <thead>
                <tr style={{borderBottom: "1px solid " + C.greenDark}}>
                  {[
                    {key: "date", label: "Data"},
                    {key: "spend", label: "Valor Usado"},
                    {key: "impressions", label: "Impressoes"},
                    {key: "clicks", label: "Cliques"},
                    {key: "conv_rate", label: "Tx Conv."},
                    {key: "contacts", label: "Contatos"},
                    {key: "cost_per_contact", label: "Custo/Contato"}
                  ].map(h => (
                    <th key={h.key} onClick={() => toggleSort(h.key)}
                      style={{padding: "10px 14px", textAlign: h.key === "date" ? "left" : "right", color: C.green, fontWeight: 600, cursor: "pointer", fontSize: 11, whiteSpace: "nowrap", userSelect: "none"}}>
                      {h.label}{arrow(h.key)}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {paged.map((r, i) => (
                  <tr key={i} style={{borderBottom: "1px solid " + C.greenDark + "44", transition: "background .15s"}}
                    onMouseEnter={e => e.currentTarget.style.background = C.greenDark + "33"}
                    onMouseLeave={e => e.currentTarget.style.background = "transparent"}>
                    <td style={{padding: "8px 14px", color: C.white, fontWeight: 500}}>{r.date}</td>
                    <td style={{padding: "8px 14px", textAlign: "right", color: C.grayLight}}>{fmtBRL(r.spend)}</td>
                    <td style={{padding: "8px 14px", textAlign: "right", color: C.grayLight}}>{fmt(r.impressions)}</td>
                    <td style={{padding: "8px 14px", textAlign: "right", color: C.grayLight}}>{fmt(r.clicks)}</td>
                    <td style={{padding: "8px 14px", textAlign: "right", color: r.conv_rate > 10 ? C.green : C.grayLight, fontWeight: r.conv_rate > 10 ? 600 : 400}}>{fmtPct(r.conv_rate)}</td>
                    <td style={{padding: "8px 14px", textAlign: "right", color: C.white, fontWeight: 600}}>{r.contacts}</td>
                    <td style={{padding: "8px 14px", textAlign: "right", color: C.grayLight}}>{r.cost_per_contact !== null ? fmtBRL(r.cost_per_contact) : "—"}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          {/* Pagination */}
          <div style={{padding: "12px 20px", display: "flex", justifyContent: "center", gap: 8, borderTop: "1px solid " + C.greenDark}}>
            <button disabled={page===0} onClick={() => setPage(p => p-1)}
              style={{...btnStyle(false), opacity: page===0 ? .3 : 1, padding: "6px 16px", fontSize: 12}}>Anterior</button>
            <span style={{color: C.gray, fontSize: 12, display: "flex", alignItems: "center"}}>{page+1} / {totalPages}</span>
            <button disabled={page >= totalPages - 1} onClick={() => setPage(p => p+1)}
              style={{...btnStyle(false), opacity: page >= totalPages-1 ? .3 : 1, padding: "6px 16px", fontSize: 12}}>Proximo</button>
          </div>
        </div>
      </div>
    </div>
  );
}
